  private static Stream<Feature> getFeaturesForChange(@NotNull ModelChange change) {
    Stream.Builder<Feature> builder = Stream.builder();
    SModelReference modelReference = SModelOperations.getPointer(change.getChangeSet().getNewModel());
    if (change instanceof AddRootChange) {
      SNodePointer nodePointer = new SNodePointer(modelReference, change.getRootId());
      builder.accept(new NodeFeature(nodePointer, change.getRootId()));
    } else if (change instanceof DeleteRootChange) {
      builder.accept(new ModelFeature(modelReference));
    } else if (change instanceof SetPropertyChange) {
      SetPropertyChange spc = ((SetPropertyChange) change);
      SNodePointer nodePointer = new SNodePointer(modelReference, spc.getAffectedNodeId());
      builder.accept(new PropertyFeature(nodePointer, spc.getProperty(), spc.getRootId()));
    } else if (change instanceof SetReferenceChange) {
      SetReferenceChange src = ((SetReferenceChange) change);
      SNodePointer nodePointer = new SNodePointer(modelReference, src.getAffectedNodeId());
      builder.accept(new ReferenceFeature(nodePointer, src.getRoleLink(), src.getRootId()));
    } else if (change instanceof NodeGroupChange) {
      NodeGroupChange ngc = ((NodeGroupChange) change);
      SNodeId parentId = ngc.getParentNodeId();
      int begin = ngc.getResultBegin();
      int end = ngc.getResultEnd();
      if (begin == end) {
        SNodePointer nodePointer = new SNodePointer(modelReference, parentId);
        builder.accept(new DeletedChildFeature(nodePointer, ngc.getRoleLink().getName(), begin, change.getRootId()));
      } else {
        List<SNode> changeChildren = ngc.getChangedCollection(true);
        for (int i = begin; i < end; i++) {
          if (i < changeChildren.size()) {
            SNodePointer nodePointer = new SNodePointer(modelReference, changeChildren.get(i).getNodeId());
            builder.accept(new NodeFeature(nodePointer, ngc.getRootId()));
          }
        }
      }
    } else if (change instanceof SetConceptChange) {
      // todo: create new feature ??
      builder.accept(new NodeFeature(new SNodePointer(modelReference, ((SetConceptChange) change).getAffectedNodeId()), change.getRootId()));
    } else if (change instanceof ModelAttributeChange || change instanceof UsedLanguageChange || change instanceof ImportedModelChange || change instanceof EngagedLanguageChange) {
      builder.accept(new ModelFeature(modelReference));
    }
    return builder.build();
  }
